import Foundation

func isPrime(_ n: Int64) -> Bool {
    if n <= 1 {
        return false
    }
    if n <= 3 {
        return true
    }
    if n % 2 == 0 || n % 3 == 0 {
        return false
    }
    var i: Int64 = 5
    var w: Int64 = 2
    while i * i <= n {
        if n % i == 0 {
            return false
        }
        i += w
        w = 6 - w
    }
    return true
}

func solve(nums: Array<Int64>) -> Int64 {
    var sumA: Int64 = 0
    var sumB: Int64 = 0

    for (index, num) in nums.enumerated() {
        if isPrime(Int64(index)) {
            sumA += num
        } else {
            sumB += num
        }
    }

    let diff = sumA - sumB
    return diff >= 0 ? diff : -diff
}
